import{_ as a,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"54. Purchased Leave","description":"","frontmatter":{"title":"54. Purchased Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","annual-leave","purchased-leave","employment"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/54-purchased-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/54-purchased-leave.md"}'),o={name:"ebas/has-managers-admin/common-terms/leave/54-purchased-leave.md"};function l(n,e,p,i,d,m){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_54-purchased-leave" tabindex="-1">54. Purchased Leave <a class="header-anchor" href="#_54-purchased-leave" aria-label="Permalink to &quot;54. Purchased Leave&quot;">​</a></h1><p><strong>54.1</strong> Full-time Employees may purchase additional annual leave, with the agreement of the Employer.</p><p><strong>54.2</strong> The amount of additional leave that may be purchased varies according to the classification of the Employee as follows:</p><p><strong>(a)</strong> Employees other than Dental Assistants employed by DHSV or Ballarat Health Service</p><p><strong>(i)</strong> Full-time Employees may purchase up to 4 weeks additional leave per year and, with the agreement of the Employer, work between 48 and 51 weeks per year. Approval rests with the Employer, who may legitimately take into account operational needs and work requirements. Agreement will not be unreasonably withheld.</p><p><strong>(ii)</strong> Where the Employer and Employee agree to a reduction in the number of working weeks, the Employee will receive additional leave as follows:</p><p>Period Additional weeks’ Total weeks’ worked leave leave</p><p>48/52 weeks 4 weeks 9 weeks</p><p>49/52 weeks 3 weeks 8 weeks</p><p>50/52 weeks 2 weeks 7 weeks</p><p>51/52 weeks 1 weeks 6 weeks</p><p><strong>(b)</strong> Dental Assistants Employed by DHSV or Ballarat Health Service:</p><p><strong>(i)</strong> Full-time Employees may purchase up to 8 weeks additional leave per year and, with the agreement of the Employer, work between 44 and 51 weeks per year.</p><p><strong>(ii)</strong> Where the Employer and Employee agree to a reduction in the number of working weeks, the Employee will receive additional leave as follows: Period Additional weeks’ Total weeks’ worked leave leave</p><p>44/52 weeks 8 weeks 13 weeks</p><p>45/52 weeks 7 weeks 12 weeks</p><p>46/52 weeks 6 weeks 11 weeks</p><p>47/52 weeks 5 weeks 10 weeks</p><p>48/52 weeks 4 weeks 9 weeks</p><p>49/52 weeks 3 weeks 8 weeks</p><p>50/52 weeks 2 weeks 7 weeks</p><p>51/52 weeks 1 weeks 6 weeks</p><p><strong>54.3</strong> Where an Employee applies for additional leave pursuant to this clause the Employer will respond to such application within four (4) weeks.</p><p><strong>54.4</strong> Where the Employer and Employee agree to a reduction in the number of working weeks, the Employee will receive a salary equal to the period worked, but spread over a 52 week period. Accrual of sick leave and long service leave will be unaffected by these arrangements.</p><p><strong>54.5</strong> The approval of purchased leave arrangements for individual Employees will be subject to annual application and approval by the Employer.</p><p><strong>54.6</strong> An Employee may revert to ordinary 52 week employment by giving the Employer no less than four weeks written notice.</p><p><strong>54.7</strong> Where an Employee so reverts to 52 week employment, appropriate pro-rata salary adjustments will be made.</p><p>Plain language terms: 48/52, buying leave, extra leave, leave purchase.</p>',28)])])}const k=a(o,[["render",l]]);export{h as __pageData,k as default};
